                    <button key={r} disabled={locked} className={`wdl-btn ${res.result===r?'active-'+r:''}`}
                      onClick={()=>!locked&&onUpdateMatch(groupKey,i,{...res,result:res.result===r?'':r})}>
                      {r==='home'?'W':r==='draw'?'D':'L'}
